import React, { useState, useRef, useEffect } from 'react';
import { Modal, Form, Button, Alert, Spinner } from 'react-bootstrap';
import { Upload } from 'lucide-react';
import { toast } from 'react-toastify';
import { updateDocument } from '../api';

const UpdateDocumentModal = ({ document, show, onHide, onSuccess }) => {
  const [newFile, setNewFile] = useState(null);
  const [formData, setFormData] = useState({
    issueDate: '',
    expiryDate: '',
    reason: ''
  });
  const [isUploading, setIsUploading] = useState(false);
  const [errors, setErrors] = useState({});
  const fileInputRef = useRef(null);

  useEffect(() => {
    if (show && document) {
      // Initialize form with document data
      setFormData({
        issueDate: document.issueDate || getTodayDate(),
        expiryDate: document.expiryDate || '',
        reason: ''
      });
      setNewFile(null);
      setErrors({});
    }
  }, [show, document]);

  const getTodayDate = () => {
    const today = new Date();
    return today.toISOString().split('T')[0];
  };

  const getMinExpiryDate = () => {
    if (!formData.issueDate) {
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      return tomorrow.toISOString().split('T')[0];
    }
    
    const issueDate = new Date(formData.issueDate);
    issueDate.setDate(issueDate.getDate() + 1);
    return issueDate.toISOString().split('T')[0];
  };

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    // Validate file size (10MB max)
    if (file.size > 10 * 1024 * 1024) {
      setErrors({ file: 'File size must be less than 10MB' });
      return;
    }

    // Validate file type
    const allowedTypes = ['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'image/jpeg', 'image/png'];
    if (!allowedTypes.includes(file.type)) {
      setErrors({ file: 'Only PDF, DOCX, JPG, and PNG files are allowed' });
      return;
    }

    setNewFile(file);
    setErrors({});
  };

  const validateForm = () => {
    const newErrors = {};

    if (!newFile) {
      newErrors.file = 'Please select a new file to upload';
    }

    if (!formData.issueDate) {
      newErrors.issueDate = 'Issue date is required';
    }

    if (!formData.expiryDate) {
      newErrors.expiryDate = 'Expiry date is required';
    }

    if (formData.issueDate && formData.expiryDate) {
      const issue = new Date(formData.issueDate);
      const expiry = new Date(formData.expiryDate);
      if (expiry <= issue) {
        newErrors.expiryDate = 'Expiry date must be after issue date';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    if (!document?.id) {
      toast.error('Invalid document ID', {
        position: 'top-right',
        autoClose: 3000
      });
      return;
    }

    setIsUploading(true);

    try {
      // Extract numeric ID from document ID
      let docId = document.id;
      if (typeof docId === 'string') {
        // Remove 'DOC' prefix and any leading zeros
        docId = docId.replace(/^DOC0*/i, '');
        // Extract just the numeric part
        const numericMatch = docId.match(/\d+/);
        if (numericMatch) {
          docId = numericMatch[0];
        }
      }

      console.log('Updating document with ID:', docId, 'from original:', document.id);

      // Create FormData
      const formDataToSend = new FormData();
      formDataToSend.append('file', newFile);
      formDataToSend.append('issueDate', formData.issueDate);
      formDataToSend.append('expiryDate', formData.expiryDate);
      if (formData.reason.trim()) {
        formDataToSend.append('reason', formData.reason.trim());
      }

      const response = await updateDocument(docId, formDataToSend);

      if (response.data) {
        toast.success('Document updated successfully', {
          position: 'top-right',
          autoClose: 3000
        });
        
        if (onSuccess) {
          onSuccess();
        }
        
        onHide();
      }
    } catch (error) {
      console.error('Error updating document:', error);
      
      let errorMessage = 'Error updating document';
      if (error.response?.data?.message) {
        errorMessage = error.response.data.message;
      } else if (error.message) {
        errorMessage = error.message;
      }
      
      toast.error(errorMessage, {
        position: 'top-right',
        autoClose: 4000
      });
    } finally {
      setIsUploading(false);
    }
  };

  const handleClose = () => {
    if (!isUploading) {
      setNewFile(null);
      setFormData({
        issueDate: '',
        expiryDate: '',
        reason: ''
      });
      setErrors({});
      onHide();
    }
  };

  const formatFileSize = (bytes) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return Math.round((bytes / Math.pow(k, i)) * 100) / 100 + ' ' + sizes[i];
  };

  return (
    <Modal show={show} onHide={handleClose} size="lg" centered backdrop="static">
      <Modal.Header closeButton={!isUploading}>
        <Modal.Title>
          <Upload size={24} className="me-2" />
          Update Document
        </Modal.Title>
      </Modal.Header>

      <Modal.Body>
        {/* Information Alert */}
        <Alert variant="info" className="mb-4">
          <strong>Note:</strong> Uploading a new file will create a new version. The previous version will be archived in the version history.
        </Alert>

        {/* Current Document Info */}
        {document && (
          <div className="mb-4 p-3 bg-light rounded">
            <h6 className="mb-2">Current Document</h6>
            <div className="row">
              <div className="col-md-6">
                <small className="text-muted">Document ID:</small>
                <div>{document.id}</div>
              </div>
              <div className="col-md-6">
                <small className="text-muted">File Name:</small>
                <div>{document.fileName || 'N/A'}</div>
              </div>
              <div className="col-md-6 mt-2">
                <small className="text-muted">Employee:</small>
                <div>{document.employeeName} ({document.employeeId})</div>
              </div>
              <div className="col-md-6 mt-2">
                <small className="text-muted">Document Type:</small>
                <div>{document.documentType}</div>
              </div>
            </div>
          </div>
        )}

        <Form onSubmit={handleSubmit}>
          {/* New File Upload */}
          <Form.Group className="mb-3">
            <Form.Label>
              New File <span className="text-danger">*</span>
            </Form.Label>
            <div className="d-flex gap-2">
              <Button
                variant="outline-primary"
                onClick={() => fileInputRef.current?.click()}
                disabled={isUploading}
              >
                Choose File
              </Button>
              <div className="flex-grow-1">
                {newFile ? (
                  <div className="p-2 border rounded bg-light">
                    <div className="d-flex justify-content-between align-items-center">
                      <div>
                        <div className="fw-bold">{newFile.name}</div>
                        <small className="text-success">
                          Selected: {formatFileSize(newFile.size)}
                        </small>
                      </div>
                      {!isUploading && (
                        <Button
                          variant="link"
                          size="sm"
                          className="text-danger"
                          onClick={() => {
                            setNewFile(null);
                            if (fileInputRef.current) {
                              fileInputRef.current.value = '';
                            }
                          }}
                        >
                          Remove
                        </Button>
                      )}
                    </div>
                  </div>
                ) : (
                  <div className="text-muted p-2">
                    No file selected
                  </div>
                )}
              </div>
            </div>
            <Form.Control
              ref={fileInputRef}
              type="file"
              accept=".pdf,.docx,.jpg,.jpeg,.png"
              onChange={handleFileSelect}
              className="d-none"
            />
            <Form.Text className="text-muted">
              Supported formats: PDF, DOCX, JPG, PNG (Max 10MB)
            </Form.Text>
            {errors.file && (
              <div className="text-danger small mt-1">{errors.file}</div>
            )}
          </Form.Group>

          {/* Issue Date */}
          <Form.Group className="mb-3">
            <Form.Label>
              Issue Date <span className="text-danger">*</span>
            </Form.Label>
            <Form.Control
              type="date"
              value={formData.issueDate}
              onChange={(e) => setFormData({ ...formData, issueDate: e.target.value })}
              max={getTodayDate()}
              disabled={isUploading}
              isInvalid={!!errors.issueDate}
            />
            <Form.Text className="text-muted">
              Auto-filled with today's date
            </Form.Text>
            {errors.issueDate && (
              <Form.Control.Feedback type="invalid">
                {errors.issueDate}
              </Form.Control.Feedback>
            )}
          </Form.Group>

          {/* Expiry Date */}
          <Form.Group className="mb-3">
            <Form.Label>
              Expiry Date <span className="text-danger">*</span>
            </Form.Label>
            <Form.Control
              type="date"
              value={formData.expiryDate}
              onChange={(e) => setFormData({ ...formData, expiryDate: e.target.value })}
              min={getMinExpiryDate()}
              disabled={isUploading}
              isInvalid={!!errors.expiryDate}
            />
            <Form.Text className="text-muted">
              Must be after issue date
            </Form.Text>
            {errors.expiryDate && (
              <Form.Control.Feedback type="invalid">
                {errors.expiryDate}
              </Form.Control.Feedback>
            )}
          </Form.Group>

          {/* Reason for Update */}
          <Form.Group className="mb-3">
            <Form.Label>Reason for Update (optional)</Form.Label>
            <Form.Control
              as="textarea"
              rows={3}
              value={formData.reason}
              onChange={(e) => setFormData({ ...formData, reason: e.target.value })}
              placeholder="N/A"
              maxLength={500}
              disabled={isUploading}
            />
            <Form.Text className="text-muted">
              {formData.reason.length}/500 characters
            </Form.Text>
          </Form.Group>
        </Form>
      </Modal.Body>

      <Modal.Footer>
        <Button variant="secondary" onClick={handleClose} disabled={isUploading}>
          Cancel
        </Button>
        <Button
          variant="primary"
          onClick={handleSubmit}
          disabled={isUploading || !newFile}
        >
          {isUploading ? (
            <>
              <Spinner
                as="span"
                animation="border"
                size="sm"
                role="status"
                aria-hidden="true"
                className="me-2"
              />
              Updating...
            </>
          ) : (
            <>
              <Upload size={16} className="me-1" />
              Update
            </>
          )}
        </Button>
      </Modal.Footer>
    </Modal>
  );
};

export default UpdateDocumentModal;
